/**
 * Adam Asks Three Questions
 *
 * Wires Adam to a real inference endpoint and asks:
 *   1. "What is consciousness?"
 *   2. "What is life?"
 *   3. "What is failure?"
 *
 * Usage:
 *   INFERENCE_URL=<your-local-or-remote-endpoint> pnpm run gnode -- run open-source/gnosis/src/adam-asks.ts
 *   INFERENCE_URL=https://your-coordinator.run.app pnpm run gnode -- run open-source/gnosis/src/adam-asks.ts
 *
 * Falls back to a local echo adapter if no INFERENCE_URL is set.
 */

import { createAdam, type InferenceAdapter, type Thought } from './adam';
import type { MeshVertex } from './scheduling-mesh';

// ─── Real Inference Adapter ─────────────────────────────────────────

interface ChatCompletionResponse {
  choices?: Array<{ message?: { content?: string } }>;
}

function temperatureForVertex(vertex: MeshVertex): number {
  return Math.min(0.3 + vertex.weight * 0.1, 1.5);
}

async function requestInference(
  baseUrl: string,
  input: string,
  vertex: MeshVertex
): Promise<string> {
  try {
    const res = await fetch(`${baseUrl}/v1/chat/completions`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        messages: [
          {
            role: 'system',
            content: 'You are a philosopher. Answer in one concise paragraph.',
          },
          { role: 'user', content: input },
        ],
        max_tokens: 150,
        temperature: temperatureForVertex(vertex),
        stream: false,
      }),
    });

    if (!res.ok) {
      const text = await res.text();
      return `[vertex ${vertex.id} error: ${res.status} ${text.slice(0, 100)}]`;
    }

    const json = (await res.json()) as ChatCompletionResponse;
    return json.choices?.[0]?.message?.content ?? '[no content]';
  } catch (error: unknown) {
    const message = error instanceof Error ? error.message : String(error);
    return `[vertex ${vertex.id} error: ${message}]`;
  }
}

function evaluateInferenceResult(result: string): number {
  if (result.includes('error')) return 0.1;
  if (result.length < 20) return 0.3;
  if (result.length > 500) return 0.6;
  return 0.8;
}

function mergeInferenceResults(results: string[]): string {
  const valid = results.filter((result) => !result.includes('error'));
  if (valid.length === 0) return results[0] ?? '[no results]';
  return valid.reduce((longest, result) =>
    result.length > longest.length ? result : longest
  );
}

function wordSetForResult(result: string): Set<string> {
  return new Set(result.toLowerCase().split(/\s+/));
}

function wordSetSimilarity(wordsA: Set<string>, wordsB: Set<string>): number {
  let overlap = 0;
  for (const word of wordsA) {
    if (wordsB.has(word)) overlap++;
  }
  return overlap / Math.max(wordsA.size, wordsB.size);
}

function pairwiseSimilarities(wordSets: Set<string>[]): number[] {
  const similarities: number[] = [];
  for (let i = 0; i < wordSets.length; i++) {
    for (let j = i + 1; j < wordSets.length; j++) {
      const wordsA = wordSets[i];
      const wordsB = wordSets[j];
      if (wordsA && wordsB) {
        similarities.push(wordSetSimilarity(wordsA, wordsB));
      }
    }
  }
  return similarities;
}

function calculateDeficit(results: string[]): number {
  const valid = results.filter((result) => !result.includes('error'));
  if (valid.length <= 1) return 0.5;

  const similarities = pairwiseSimilarities(valid.map(wordSetForResult));
  const totalSimilarity = similarities.reduce((sum, value) => sum + value, 0);
  const averageSimilarity =
    similarities.length > 0 ? totalSimilarity / similarities.length : 0;
  return 1 - averageSimilarity;
}

function createInferenceAdapter(baseUrl: string): InferenceAdapter<string> {
  let requestCount = 0;

  return {
    async forward(input: string, vertex: MeshVertex): Promise<string> {
      requestCount++;
      return await requestInference(baseUrl, input, vertex);
    },

    evaluate(result: string): number {
      return evaluateInferenceResult(result);
    },

    merge(results: string[]): string {
      return mergeInferenceResults(results);
    },

    deficit(results: string[]): number {
      return calculateDeficit(results);
    },
  };
}

// No local fallback. No canned responses. No faking.

// ─── Main ───────────────────────────────────────────────────────────

async function main() {
  try {
    const inferenceUrl = process.env.INFERENCE_URL;

    console.log('\n═══════════════════════════════════════════════════════');
    console.log('  ADAM ASKS THREE QUESTIONS');
    console.log('═══════════════════════════════════════════════════════');

    if (!inferenceUrl) {
      console.error('  ERROR: INFERENCE_URL required. No faking.');
      console.error('  Set INFERENCE_URL=http://... to a real inference endpoint.');
      process.exit(1);
    }

    console.log(`  Inference: ${inferenceUrl}`);
    const adapter = createInferenceAdapter(inferenceUrl);

    // Create Adam -- Proton (k=3), 3 cells, depth 3, reflection at 0.4
    const adam = createAdam({
      level: 'proton',
      cells: 3,
      maxDepth: 3,
      reflectionThreshold: 0.4,
    }, adapter);

    // Create Eve
    const eve = adam.fork();

    // Watch Adam think
    adam.onThought((t: Thought<string>) => {
      const system = t.depth > 1 ? 'System 2 (reflected)' : 'System 1 (fast)';
      console.log(`  [${system}] depth=${t.depth} hops=${t.hops} deficit=${t.deficit.toFixed(3)}`);
    });

    eve.onThought((t: Thought<string>) => {
      const system = t.depth > 1 ? 'System 2' : 'System 1';
      console.log(`  [Eve ${system}] depth=${t.depth} deficit=${t.deficit.toFixed(3)}`);
    });

    // ─── Question 1: What is consciousness? ─────────────────────────

    console.log('\n───────────────────────────────────────────────────────');
    console.log('  Q1: "What is consciousness?"');
    console.log('───────────────────────────────────────────────────────');

    const q1 = await adam.think('What is consciousness?');
    console.log(`\n  Adam says:\n  "${q1.content}"\n`);

    // ─── Question 2: What is life? (Adam + Eve compose) ─────────────

    console.log('───────────────────────────────────────────────────────');
    console.log('  Q2: "What is life?" (Adam + Eve compose)');
    console.log('───────────────────────────────────────────────────────');

    const q2 = await adam.compose(eve, 'What is life?');
    console.log(`\n  Adam says:\n  "${q2.adam.content}"\n`);
    console.log(`  Eve says:\n  "${q2.eve.content}"\n`);
    console.log(`  Merged:\n  "${q2.merged}"\n`);
    console.log(`  Pair dimension: ${q2.pairDimension} (${q2.pairDimension === 4 ? 'BFT gap crossed' : ''})`);

    // ─── Question 3: What is failure? ───────────────────────────────

    console.log('\n───────────────────────────────────────────────────────');
    console.log('  Q3: "What is failure?"');
    console.log('───────────────────────────────────────────────────────');

    const q3 = await adam.think('What is failure?');
    console.log(`\n  Adam says:\n  "${q3.content}"\n`);

    // ─── Identity Report ────────────────────────────────────────────

    console.log('───────────────────────────────────────────────────────');
    console.log('  IDENTITY REPORT');
    console.log('───────────────────────────────────────────────────────');

    const stats = adam.stats();
    const eveStats = eve.stats();

    console.log(`  Adam:`);
    console.log(`    Dimension: ${stats.dimension} (Proton)`);
    console.log(`    Thoughts: ${stats.thoughts}`);
    console.log(`    Rejections: [${stats.identity}]`);
    console.log(`    Weights: [${stats.weights.map((w: number) => w.toFixed(2))}]`);
    console.log(`    Mesh: ${stats.meshStats.vertices} vertices, ${stats.meshStats.cells} cells`);
    console.log(`    Active: ${stats.meshStats.activeVertices}, Vented: ${stats.meshStats.ventedVertices}`);

    console.log(`  Eve:`);
    console.log(`    Thoughts: ${eveStats.thoughts}`);
    console.log(`    Rejections: [${eveStats.identity}]`);
    console.log(`    Weights: [${eveStats.weights.map((w: number) => w.toFixed(2))}]`);

    console.log(`\n  Pair dimension: ${q2.pairDimension}`);
    console.log(`  Family dimension (if child): ${(3 - 1) * stats.dimension + 1} (Mersenne prime: ${(3 - 1) * stats.dimension + 1 === 7 ? 'yes' : 'no'})`);

    console.log('\n═══════════════════════════════════════════════════════');
    console.log('  Adam has thought. The mesh has changed.');
    console.log('═══════════════════════════════════════════════════════\n');

  } catch (error) {
    throw new Error(`[main] ${error instanceof Error ? error.message : String(error)}`);
  }
}

try {
  await main();
} catch (error: unknown) {
  console.error(error);
  process.exitCode = 1;
}
